module counter (clk, rst, mode, cnt);

    input  wire clk;
    input  wire rst;
    input  wire mode;
    output reg signed [9:0] cnt = 10'sd42;

    reg signed [9:0] summand;

    always @* begin
        summand = 10'sd0;
        if (mode) begin
            if (cnt != -10'sd111) begin
                if (cnt <= 10'sd306) begin
                    summand = 10'sd4;
                end
            end else if (cnt <= 10'sd302) begin
                summand = 10'sd8;
            end
        // mode = 0
        end else begin
            if (cnt != -10'sd96) begin
                if (cnt >= -10'sd376 ) begin
                    summand = -10'sd11;
                end
            end else if (cnt >= -10'sd365) begin
                summand = -10'sd22;
            end
        end
    end

    always @(posedge clk) begin
        if (rst)
            cnt <= 10'sd42;
        else begin
            cnt <= cnt + summand;
        end
    end
endmodule
